            "title": "1st month: Gets excited when you talk to him",
            "created_at": "\u003Ctime datetime=\"2025-05-22T13:29:26+02:00\" class=\"datetime\"\u003EThu, 05/22/2025 - 13:29\u003C/time\u003E\n",
            "updated_at": "\u003Ctime datetime=\"2026-02-10T06:20:33+01:00\" class=\"datetime\"\u003ETue, 02/10/2026 - 06:20\u003C/time\u003E\n",
            "summary": "",
            "body": "",
