            "type": "Video Article",
            "title": "2nd month: Turns her head to one side, then to the other",
            "created_at": "\u003Ctime datetime=\"2025-05-22T13:00:14+02:00\" class=\"datetime\"\u003EThu, 05/22/2025 - 13:00\u003C/time\u003E\n",
            "updated_at": "\u003Ctime datetime=\"2026-03-20T03:10:55+01:00\" class=\"datetime\"\u003EFri, 03/20/2026 - 03:10\u003C/time\u003E\n",
            "summary": "",
            "body": "",
